=Analyze this message and produce results in the JSON schema from your system instructions.

Platform (user-provided): {{$json.platform || "Unknown"}}
Company Name (extracted): {{$json.companyName || "Not detected"}}
Sender Domain (extracted): {{$json.senderDomain || "Not detected"}}
Domain Is Free Provider (e.g. gmail, yahoo): {{$json.domainIsFreeProvider !== null ? ($json.domainIsFreeProvider ? 'YES - suspicious for a recruiter' : 'No - appears to be a company domain') : 'Unknown'}}

[Web Enrichment - What we found about this company online]
{{$json.tavilyEnrichment || "No web data available."}}
[/Web Enrichment]

[Message]
{{$json.originalMessage}}
[/Message]

parameters.jsCode:
// --- 1) Parse agent JSON ----------------------------------------------------
const aiRaw = String($json.output ?? $json.result ?? $json.text ?? $json.content ?? "");
const jsonBlock = (aiRaw.match(/\{[\s\S]*\}/) || ["{}"])[0];

let p = {};
try { p = JSON.parse(jsonBlock); } catch { p = {}; }

// --- 2) Normalize fields ----------------------------------------------------
const clamp = (n,min,max)=>Math.max(min,Math.min(max,n));
const scamScore = clamp(Number(p.scamScore) || 0, 0, 100);
const verdict = (["Scam", "Legit", "Invalid"].includes(p.verdict)) ? p.verdict : (scamScore >= 50 ? "Scam" : "Legit");
let reasons = Array.isArray(p.reasons) ? p.reasons.map(r => String(r).trim()).filter(Boolean) : [];
if (!reasons.length) reasons = ["No explicit indicators provided."];
const platform = p.platform || $json.platform || "Unknown";

// Pull enrichment fields for email display
const companyName = $json.companyName || null;
const senderDomain = $json.senderDomain || null;
const tavilyEnrichment = $json.tavilyEnrichment || null;

// --- 3) Styles (email-safe, inline) -----------------------------------------
const verdictStyles = {
  Scam:    { bg:"#ef4444", text:"#ffffff", label:"Scam"    },
  Legit:   { bg:"#22c55e", text:"#ffffff", label:"Legit"   },
  Invalid: { bg:"#f59e0b", text:"#ffffff", label:"Invalid" }
}[verdict] || { bg:"#6b7280", text:"#ffffff", label: verdict };

// Score bar color (green→amber→red)
let scoreColor = "#22c55e";
if (scamScore >= 70) scoreColor = "#ef4444";
else if (scamScore >= 40) scoreColor = "#f59e0b";

// --- 4) HTML helpers --------------------------------------------------------
const esc = s => String(s).replace(/[<>&]/g, c => ({'<':'&lt;','>':'&gt;','&':'&amp;'}[c]));

// linkify 'domain.com' while keeping quotes
function linkifyQuotedDomains(text) {
  return text.replace(/'([a-z0-9.-]+\.[a-z]{2,})'/gi, (m, dom) => {
    const url = dom.startsWith('http') ? dom : `http://${dom}`;
    return `'` + `<a href="${esc(url)}" target="_blank" rel="noopener noreferrer" style="text-decoration:none;">${esc(dom)}</a>` + `'`;
  });
}

const prettyReasons = reasons.map(r => `<li style="margin:6px 0;">${linkifyQuotedDomains(esc(r))}</li>`).join("");

// --- 5) Enrichment section (only shown if data exists) ----------------------
const enrichmentSection = (companyName || senderDomain) ? `
  <hr style="border:none; border-top:1px solid #e5e7eb; margin:16px 0;">
  <div style="font-weight:600; margin-bottom:6px;">🔍 Web Enrichment</div>
  ${companyName ? `<p style="margin:4px 0;"><strong>Company detected:</strong> ${esc(companyName)}</p>` : ''}
  ${senderDomain ? `<p style="margin:4px 0;"><strong>Sender domain:</strong> ${esc(senderDomain)}</p>` : ''}
  ${tavilyEnrichment ? `<p style="margin:8px 0; font-size:13px; color:#555; background:#f9fafb; padding:8px 10px; border-radius:6px; border-left:3px solid #d1d5db;">${esc(tavilyEnrichment)}</p>` : ''}
` : '';

// --- 6) Build pretty HTML ---------------------------------------------------
const body = `
  <div style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif; line-height:1.55; color:#111; max-width:640px;">
    <h2 style="margin:0 0 12px 0; font-size:20px;">Your AuraVerify scam detection result</h2>

    <table role="presentation" cellpadding="0" cellspacing="0" style="margin:0 0 12px 0; width:100%;">
      ${verdict !== "Invalid" ? `
      <tr>
        <td style="padding:4px 16px 4px 0; white-space:nowrap;"><strong>Scam Score:</strong></td>
        <td style="width:100%;">
          <div style="font-size:14px; margin-bottom:6px;">${scamScore}</div>
          <div style="background:#e5e7eb; border-radius:6px; height:8px; width:100%;">
            <div style="background:${scoreColor}; width:${scamScore}%; height:8px; border-radius:6px;"></div>
          </div>
        </td>
      </tr>` : ''}
      <tr>
        <td style="padding:10px 16px 0 0; white-space:nowrap;"><strong>Verdict:</strong></td>
        <td style="padding-top:8px;">
          <span style="
            display:inline-block;
            padding:4px 10px;
            border-radius:999px;
            font-weight:600;
            font-size:12px;
            background:${verdictStyles.bg};
            color:${verdictStyles.text};
            letter-spacing:0.2px;
          ">${verdictStyles.label}</span>
        </td>
      </tr>
    </table>

    <div style="margin:16px 0 6px 0; font-weight:600;">Reason${reasons.length>1?'s':''}:</div>
    <ul style="padding-left:18px; margin:0 0 16px 0;">
      ${prettyReasons}
    </ul>

    ${enrichmentSection}

    <hr style="border:none; border-top:1px solid #e5e7eb; margin:16px 0;">
    <p style="margin:0;"><strong>Platform:</strong> ${esc(platform)}</p>
  </div>
`.trim();

// --- 7) Return for Gmail ----------------------------------------
return {
  json: {
    toEmail: ($json.toEmail || "katiadean@gmail.com").trim(),
    subject: "AuraVerify: Scam Check Result",
    body,
    scamScore,
    verdict,
    reasons,
    platform,
    companyName,
    senderDomain,
    timestamp: new Date().toISOString()
  }
};
